export const bodyHtml = "<header>\n        <div class=\"container nav-wrapper\">\n            <a href=\"/\" class=\"logo-text\">\n                Noor<span style=\"color: var(--accent);\">Link</span><sup class=\"logo-tm\">TM</sup>\n            </a>\n            \n            <nav class=\"nav-links\" id=\"navLinks\">\n                <a href=\"/about\">About</a>\n                <a href=\"/destinations\">Destinations</a>\n                <a href=\"/plans\" style=\"color: var(--primary);\">Plans</a>\n                <a href=\"/support\">Support</a>\n                <a href=\"/dashboard\" class=\"btn-nav\">My eSIMs</a>\n            </nav>\n\n            <div class=\"mobile-toggle\" onclick=\"toggleMenu()\"><i class=\"fas fa-bars\"></i></div>\n        </div>\n    </header>\n\n    <div class=\"container\">\n        <!-- PAGE HEADER -->\n        <div class=\"page-header\">\n            <h1>Your Complete 4-Plan Structure</h1>\n            <p>Choose the perfect eSIM plan for your travel needs. Simple, transparent pricing.</p>\n        </div>\n\n        <!-- SEARCH SECTION -->\n        <div class=\"search-section\">\n            <div class=\"search-wrapper\">\n                <div class=\"search-box\">\n                    <input type=\"text\" \n                           id=\"countrySearch\" \n                           class=\"search-input\"\n                           placeholder=\"🔍 Search for a country (USA, UAE, Japan, etc.)...\"\n                           autocomplete=\"off\">\n                    <button class=\"search-btn\" onclick=\"performSearch()\">\n                        <i class=\"fas fa-search\"></i>\n                    </button>\n                </div>\n                <div id=\"searchResults\" class=\"search-results\"></div>\n            </div>\n\n            <!-- QUICK SELECTION -->\n            <div class=\"choice-section\">\n                <h3 class=\"section-label\">Popular Destinations</h3>\n                <div class=\"choice-buttons\">\n                    <button class=\"choice-btn\" onclick=\"loadCountryPlans('usa')\">\n                        🇺🇸 USA\n                    </button>\n                    <button class=\"choice-btn\" onclick=\"loadCountryPlans('uae')\">\n                        🇦🇪 UAE\n                    </button>\n                    <button class=\"choice-btn\" onclick=\"loadCountryPlans('saudi-arabia')\">\n                        🇸🇦 Saudi Arabia\n                    </button>\n                    <button class=\"choice-btn\" onclick=\"loadCountryPlans('japan')\">\n                        🇯🇵 Japan\n                    </button>\n                    <button class=\"choice-btn\" onclick=\"loadCountryPlans('uk')\">\n                        🇬🇧 UK\n                    </button>\n                </div>\n            </div>\n        </div>\n\n        <!-- PLANS SECTION (DYNAMICALLY LOADED) -->\n        <section class=\"plans-section\" id=\"plansSection\">\n            <!-- Country plans will be loaded here -->\n        </section>\n\n        <!-- HOW IT WORKS -->\n        <section class=\"steps-section\" id=\"how-it-works\">\n            <div class=\"container\">\n                <div style=\"text-align:center;\">\n                    <h2 style=\"font-size: 2.5rem; color: var(--primary);\">How It Works</h2>\n                    <p style=\"color: var(--text-muted); font-size: 1.2rem; margin-top: 10px;\">Get online in 3 simple steps</p>\n                </div>\n                \n                <div class=\"steps-grid\">\n                    <div class=\"step-card\">\n                        <div class=\"step-icon\"><i class=\"fas fa-mobile-alt\"></i></div>\n                        <h3>1. Verify & Buy</h3>\n                        <p>Check if your phone is compatible, then choose your destination and data plan.</p>\n                    </div>\n                    <div class=\"step-card\">\n                        <div class=\"step-icon\"><i class=\"fas fa-envelope-open-text\"></i></div>\n                        <h3>2. Get Your Plan</h3>\n                        <p>Receive your QR code and activation details instantly via email.</p>\n                    </div>\n                    <div class=\"step-card\">\n                        <div class=\"step-icon\"><i class=\"fas fa-qrcode\"></i></div>\n                        <h3>3. Scan & Connect</h3>\n                        <p>Scan the code in your settings to install the eSIM. Turn on roaming and enjoy!</p>\n                    </div>\n                </div>\n            </div>\n        </section>\n\n    </div>\n\n    <footer>\n        <div class=\"container footer-grid\">\n            <div>\n                <a href=\"/\" class=\"logo-text\" style=\"color:white !important;\">\n                    Noor<span style=\"color:var(--accent);\">Link</span><sup class=\"logo-tm\">TM</sup>\n                </a>\n                <p style=\"margin-top: 20px; line-height: 1.8;\">\n                    Making global travel simple.<br>\n                    📍 MOUNTAIN ROAD PL NE, Suite R<br>\n                    ALBUQUERQUE, NM 87110\n                </p>\n            </div>\n            <div>\n                <h4>Company</h4>\n                <div class=\"footer-list\">\n                    <a href=\"/about\">About Us</a>\n                    <a href=\"/support\">Contact Support</a>\n                    <a href=\"#\">Partner Program</a>\n                </div>\n            </div>\n            <div>\n                <h4>Legal</h4>\n                <div class=\"footer-list\">\n                    <a href=\"/privacy\">Privacy Policy</a>\n                    <a href=\"/terms\">Terms of Service</a>\n                    <a href=\"/refund\">Refund Policy</a>\n                    <a href=\"/kyc\">KYC / AML Policy</a>\n                </div>\n            </div>\n        </div>\n        <div class=\"footer-bottom\">\n            &copy; 2026 NoorLink.co. All rights reserved.\n        </div>\n    </footer>\n\n    <a href=\"https://wa.me/17184729390\" class=\"whatsapp-float\" target=\"_blank\" title=\"Chat on WhatsApp\"></a>";
export const scripts = ["// Mobile menu toggle\n    function toggleMenu() { \n        document.getElementById('navLinks').classList.toggle('active'); \n    }\n\n    // Wait for database to load\n    document.addEventListener('DOMContentLoaded', function() {\n        // Load database first\n        if (typeof noorlinkDatabase === 'undefined') {\n            console.error('Database not loaded');\n            loadDatabaseFallback();\n        } else {\n            initializePlantsPage();\n        }\n    });\n\n    function initializePlantsPage() {\n        // 1. FIRST check URL parameter\n        const urlParams = new URLSearchParams(window.location.search);\n        const countryCode = urlParams.get('country');\n        \n        // 2. Load country from URL if available, otherwise default to USA\n        if (countryCode) {\n            console.log(\"Loading country from URL:\", countryCode);\n            loadCountryPlans(countryCode);\n        } else {\n            console.log(\"No country in URL, defaulting to USA\");\n            loadCountryPlans('usa');\n        }\n        \n        // 3. Search event listeners\n        const searchInput = document.getElementById('countrySearch');\n        searchInput.addEventListener('input', performSearch);\n        \n        // Click outside to close search results\n        document.addEventListener('click', function(e) {\n            if (!e.target.closest('#countrySearch') && !e.target.closest('#searchResults')) {\n                hideSearchResults();\n            }\n        });\n        \n        // Enter key for search\n        searchInput.addEventListener('keypress', function(e) {\n            if (e.key === 'Enter') {\n                performSearch();\n                if (searchInput.value.trim()) {\n                    const firstResult = document.querySelector('.search-result-item');\n                    if (firstResult) firstResult.click();\n                }\n            }\n        });\n    }\n\n    // ====== SEARCH FUNCTIONS ======\n    function performSearch() {\n        const query = document.getElementById('countrySearch').value.toLowerCase().trim();\n        const resultsDiv = document.getElementById('searchResults');\n        \n        if (query.length < 2) {\n            resultsDiv.style.display = 'none';\n            return;\n        }\n        \n        // Use database search if available\n        let matches = [];\n        if (window.noorlinkDatabase && window.noorlinkDatabase.searchCountries) {\n            matches = window.noorlinkDatabase.searchCountries(query);\n        } else {\n            // Fallback search\n            matches = searchCountriesFallback(query);\n        }\n        \n        let html = '';\n        \n        if (matches.length > 0) {\n            matches.forEach(country => {\n                html += `\n                    <div class=\"search-result-item\" onclick=\"selectCountry('${country.code}')\">\n                        <div class=\"search-result-info\">\n                            <span class=\"country-flag\">${country.flag}</span>\n                            <span class=\"country-name\">${country.name}</span>\n                            <span class=\"premium-badge\">4-Plan Structure</span>\n                        </div>\n                        <div class=\"search-result-type\">\n                            Click to view plans\n                        </div>\n                    </div>\n                `;\n            });\n        } else {\n            html = `\n                <div class=\"search-result-item\" onclick=\"loadCountryPlans('usa')\">\n                    <div class=\"search-result-info\">\n                        <span class=\"country-flag\">🇺🇸</span>\n                        <span class=\"country-name\">United States</span>\n                        <span class=\"premium-badge\">Sample Plans</span>\n                    </div>\n                    <div class=\"search-result-type\">\n                        View our 4-plan structure\n                    </div>\n                </div>\n            `;\n        }\n        \n        resultsDiv.innerHTML = html;\n        resultsDiv.style.display = 'block';\n    }\n\n    function hideSearchResults() {\n        document.getElementById('searchResults').style.display = 'none';\n    }\n\n    function selectCountry(countryCode) {\n        loadCountryPlans(countryCode);\n        hideSearchResults();\n        document.getElementById('countrySearch').value = '';\n    }\n\n    // ====== LOAD COUNTRY PLANS ======\n    function loadCountryPlans(countryCode) {\n        let countryData;\n        \n        if (window.noorlinkDatabase && window.noorlinkDatabase.getCountryDisplayData) {\n            countryData = window.noorlinkDatabase.getCountryDisplayData(countryCode);\n        } else {\n            // Fallback to basic data\n            countryData = getFallbackCountryData(countryCode);\n        }\n        \n        if (!countryData) {\n            // Fallback to USA if country not found\n            alert('Detailed plans for this country are coming soon! Showing USA plans as an example of our 4-plan structure.');\n            loadCountryPlans('usa');\n            return;\n        }\n        \n        const plansSection = document.getElementById('plansSection');\n        plansSection.innerHTML = generateCountryPlansHTML(countryData);\n        \n        // Scroll to plans section\n        plansSection.scrollIntoView({ behavior: 'smooth' });\n        \n        // Update active button\n        document.querySelectorAll('.choice-btn').forEach(btn => {\n            btn.classList.remove('active');\n            if (btn.onclick && btn.onclick.toString().includes(countryCode)) {\n                btn.classList.add('active');\n            }\n        });\n    }\n\n    function generateCountryPlansHTML(countryData) {\n        const { flag, name, displayName, plans } = countryData;\n        \n        // Check if family plan exists and has lines property\n        const familyLines = plans.family && plans.family.lines ? plans.family.lines : 4;\n        const familyData = plans.family && plans.family.sharedData ? plans.family.sharedData : \n                          plans.family && plans.family.data ? plans.family.data : '50 GB';\n        \n        // Get clean country name (remove \"PLANS\" if present)\n        const cleanCountryName = displayName.replace(' PLANS', '');\n        \n        return `\n            <!-- COUNTRY HEADER -->\n            <div class=\"country-header\">\n                <div class=\"flag\">${flag}</div>\n                <h2>${displayName}</h2>\n                <p>Choose from our complete 4-plan structure</p>\n            </div>\n\n            <!-- 4-PLAN GRID -->\n            <div class=\"plans-grid\">\n                <!-- BASIC PLAN -->\n                <div class=\"plan-card basic\">\n                    <div class=\"plan-badge\">Plan 1</div>\n                    <h3 class=\"plan-name\">${plans.basic.name}</h3>\n                    <div class=\"plan-positioning\">${plans.basic.positioning || 'Perfect for light data usage'}</div>\n                    <div class=\"plan-data\">${plans.basic.data}</div>\n                    <div class=\"plan-duration\">${plans.basic.days} days</div>\n                    <div class=\"plan-price\">$${plans.basic.price.toFixed(2)}</div>\n                    <ul class=\"plan-features\">\n                        ${(plans.basic.features || getDefaultFeatures('basic')).map(feature => `<li>${feature}</li>`).join('')}\n                    </ul>\n                    <button class=\"plan-btn\" \n                            data-country=\"${cleanCountryName}\"\n                            data-plan=\"${plans.basic.name}\"\n                            data-price=\"${plans.basic.price}\"\n                            onclick=\"handlePlanSelection(this)\">\n                        Get Basic Plan\n                    </button>\n                </div>\n\n                <!-- STANDARD PLAN -->\n                <div class=\"plan-card standard\">\n                    <div class=\"plan-badge\">Plan 2</div>\n                    ${plans.standard.popular ? '<div class=\"popular-badge\">✓ Most Popular</div>' : ''}\n                    <h3 class=\"plan-name\">${plans.standard.name}</h3>\n                    <div class=\"plan-positioning\">${plans.standard.positioning || 'Best balance of data & value'}</div>\n                    <div class=\"plan-data\">${plans.standard.data}</div>\n                    <div class=\"plan-duration\">${plans.standard.days} days</div>\n                    <div class=\"plan-price\">$${plans.standard.price.toFixed(2)}</div>\n                    <ul class=\"plan-features\">\n                        ${(plans.standard.features || getDefaultFeatures('standard')).map(feature => `<li>${feature}</li>`).join('')}\n                    </ul>\n                    <button class=\"plan-btn\" \n                            data-country=\"${cleanCountryName}\"\n                            data-plan=\"${plans.standard.name}\"\n                            data-price=\"${plans.standard.price}\"\n                            onclick=\"handlePlanSelection(this)\">\n                        Get Standard Plan\n                    </button>\n                </div>\n\n                <!-- PREMIUM PLAN -->\n                <div class=\"plan-card premium\">\n                    <div class=\"plan-badge\">Plan 3</div>\n                    <h3 class=\"plan-name\">${plans.premium.name}</h3>\n                    <div class=\"plan-positioning\">${plans.premium.positioning || 'Unlimited data for heavy users'}</div>\n                    <div class=\"plan-data\">${plans.premium.data}</div>\n                    <div class=\"plan-duration\">${plans.premium.days} days</div>\n                    <div class=\"plan-price\">$${plans.premium.price.toFixed(2)}</div>\n                    <ul class=\"plan-features\">\n                        ${(plans.premium.features || getDefaultFeatures('premium')).map(feature => `<li>${feature}</li>`).join('')}\n                    </ul>\n                    <button class=\"plan-btn\" \n                            data-country=\"${cleanCountryName}\"\n                            data-plan=\"${plans.premium.name}\"\n                            data-price=\"${plans.premium.price}\"\n                            onclick=\"handlePlanSelection(this)\">\n                        Get Premium Plan\n                    </button>\n                </div>\n\n                <!-- FAMILY BUNDLE -->\n                <div class=\"plan-card family\">\n                    <div class=\"plan-badge\">Plan 4</div>\n                    <h3 class=\"plan-name\">${plans.family.name}</h3>\n                    <div class=\"plan-positioning\">${plans.family.positioning || 'Perfect for groups & families'}</div>\n                    <div class=\"plan-data\">${familyData}</div>\n                    <div class=\"plan-duration\">${familyLines} lines • ${plans.family.days} days</div>\n                    <div class=\"plan-price\">$${plans.family.price.toFixed(2)}</div>\n                    <div class=\"plan-savings\">Great value for multiple lines</div>\n                    <ul class=\"plan-features\">\n                        ${(plans.family.features || getDefaultFeatures('family')).map(feature => `<li>${feature}</li>`).join('')}\n                    </ul>\n                    <button class=\"plan-btn\" \n                            data-country=\"${cleanCountryName}\"\n                            data-plan=\"${plans.family.name}\"\n                            data-price=\"${plans.family.price}\"\n                            onclick=\"handlePlanSelection(this)\">\n                        Get Family Bundle\n                    </button>\n                </div>\n            </div>\n\n            <!-- FLEX DATA OPTION -->\n            <div class=\"flex-data-card\">\n                <h3>Flex Data - Pay As You Go</h3>\n                <p class=\"flex-subtitle\">Perfect if you're unsure about your data needs</p>\n                \n                <div class=\"flex-grid\">\n                    <div class=\"flex-how-it-works\">\n                        <h4>How it works:</h4>\n                        <div class=\"flex-step\">\n                            <strong>Buy 5GB starting pack</strong>\n                            <p>Start with 5GB for $25. Perfect base for your trip.</p>\n                        </div>\n                        <div class=\"flex-step\">\n                            <strong>Use data as needed</strong>\n                            <p>Browse, stream, and connect normally.</p>\n                        </div>\n                        <div class=\"flex-step\">\n                            <strong>Get alert at 80% used</strong>\n                            <p>We'll notify you before you run out of data.</p>\n                        </div>\n                        <div class=\"flex-step\">\n                            <strong>Top up easily in dashboard</strong>\n                            <p>Add more data instantly: $5/GB</p>\n                        </div>\n                        <div class=\"flex-step\">\n                            <strong>No contracts, no waste</strong>\n                            <p>Only pay for what you actually use.</p>\n                        </div>\n                    </div>\n                    <div class=\"flex-highlight\">\n                        <div class=\"flex-price\">$5<span>/GB</span></div>\n                        <div class=\"plan-duration\">30-day validity</div>\n                        <ul class=\"flex-features\">\n                            <li>Start with 5GB ($25)</li>\n                            <li>Add more as needed</li>\n                            <li>No overage charges</li>\n                            <li>30-day validity</li>\n                            <li>Pay for what you use</li>\n                        </ul>\n                        <button class=\"flex-btn\" \n                                data-country=\"${cleanCountryName}\"\n                                data-plan=\"Flex Data\"\n                                data-price=\"25\"\n                                onclick=\"handlePlanSelection(this)\">\n                            Start with Flex Data - $25\n                        </button>\n                        <p style=\"font-size: 0.9rem; color: var(--text-muted); margin-top: 15px;\">\n                            Need flexibility? This is for you!\n                        </p>\n                    </div>\n                </div>\n            </div>\n        `;\n    }\n\n    // ====== NEW: CENTRALIZED PLAN SELECTION HANDLER ======\n    function handlePlanSelection(button) {\n        // Get data from button attributes (guaranteed to be correct)\n        const country = button.getAttribute('data-country');\n        const plan = button.getAttribute('data-plan');\n        const price = parseFloat(button.getAttribute('data-price'));\n        \n        console.log(\"✅ PLAN SELECTION:\", { \n            country: country, \n            plan: plan, \n            price: price \n        });\n        \n        // Call the existing selectPlan function with correct data\n        selectPlan(country, plan, price);\n    }\n\n    // ====== PURCHASE FUNCTION (KEEP THIS AS IS) ======\n    window.selectPlan = function(countryName, planName, price) {\n        console.log(\"💾 SAVING TO CHECKOUT:\", { \n            countryName: countryName, \n            planName: planName, \n            price: price \n        });\n        \n        // Store selection in localStorage\n        const selection = {\n            country: countryName,\n            plan: planName,\n            price: price,\n            timestamp: new Date().toISOString()\n        };\n        \n        localStorage.setItem('selectedPlan', JSON.stringify(selection));\n        \n        // Redirect to checkout with the correct country\n        window.location.href = `checkout.html?plan=${encodeURIComponent(planName)}&price=${price}&country=${encodeURIComponent(countryName)}`;\n    };\n\n    window.selectFlexData = function(countryName) {\n        const selection = {\n            country: countryName,\n            plan: 'Flex Data',\n            price: 25.00,\n            isFlex: true,\n            timestamp: new Date().toISOString()\n        };\n        \n        localStorage.setItem('selectedPlan', JSON.stringify(selection));\n        window.location.href = `checkout.html?plan=Flex%20Data&price=25&country=${encodeURIComponent(countryName)}`;\n    };\n\n    function getDefaultFeatures(planType) {\n        const features = {\n            basic: [\n                'Basic data allowance',\n                'Essential connectivity',\n                'Email support',\n                'Reliable coverage'\n            ],\n            standard: [\n                'Generous data allocation',\n                'Priority network speeds',\n                '24/7 chat support',\n                'Hotspot enabled'\n            ],\n            premium: [\n                'Unlimited high-speed data',\n                'VIP priority access',\n                'Premium network coverage',\n                'Unlimited hotspot'\n            ],\n            family: [\n                'Multiple eSIM lines',\n                'Shared data pool',\n                'Family management dashboard',\n                'Great value for groups'\n            ]\n        };\n        return features[planType] || features.basic;\n    }\n\n    // ====== FALLBACK FUNCTIONS ======\n    function loadDatabaseFallback() {\n        console.log('Using fallback data');\n        // Initialize with fallback data\n        initializePlantsPage();\n    }\n\n    function searchCountriesFallback(query) {\n        const fallbackCountries = [\n            { code: 'usa', name: 'United States', flag: '🇺🇸' },\n            { code: 'uae', name: 'United Arab Emirates', flag: '🇦🇪' },\n            { code: 'saudi-arabia', name: 'Saudi Arabia', flag: '🇸🇦' },\n            { code: 'japan', name: 'Japan', flag: '🇯🇵' },\n            { code: 'uk', name: 'United Kingdom', flag: '🇬🇧' },\n            { code: 'france', name: 'France', flag: '🇫🇷' },\n            { code: 'germany', name: 'Germany', flag: '🇩🇪' },\n            { code: 'australia', name: 'Australia', flag: '🇦🇺' }\n        ];\n        \n        return fallbackCountries.filter(country => \n            country.name.toLowerCase().includes(query) || \n            country.code.toLowerCase().includes(query)\n        );\n    }\n\n    function getFallbackCountryData(countryCode) {\n        const fallbackData = {\n            'usa': {\n                flag: '🇺🇸',\n                name: 'United States',\n                displayName: 'UNITED STATES',\n                plans: {\n                    basic: { name: 'Basic', data: '3 GB', days: 7, price: 9.99, positioning: 'Just enough to stay connected' },\n                    standard: { name: 'Standard', data: '10 GB', days: 15, price: 19.99, positioning: 'Perfect balance of data & value', popular: true },\n                    premium: { name: 'Premium', data: 'Unlimited*', days: 30, price: 64.99, positioning: 'Truly unlimited, worry-free browsing' },\n                    family: { name: 'Family Bundle', lines: 4, data: '50 GB', days: 30, price: 89.99, positioning: 'One plan for everyone traveling together' }\n                }\n            },\n            'uae': {\n                flag: '🇦🇪',\n                name: 'United Arab Emirates',\n                displayName: 'UNITED ARAB EMIRATES',\n                plans: {\n                    basic: { name: 'Basic', data: '5 GB', days: 7, price: 14.99, positioning: 'Essential UAE connectivity' },\n                    standard: { name: 'Standard', data: '10 GB', days: 15, price: 24.99, positioning: 'Perfect balance for UAE travel', popular: true },\n                    premium: { name: 'Premium', data: 'Unlimited*', days: 30, price: 69.99, positioning: 'Unlimited UAE experience' },\n                    family: { name: 'Family Bundle', lines: 4, data: '60 GB', days: 30, price: 99.99, positioning: 'Perfect for family UAE vacations' }\n                }\n            }\n        };\n        \n        return fallbackData[countryCode] || fallbackData['usa'];\n    }"];
